mapper.select:
SELECT b.province_code, c.name as 'provinceName', sum(a.total_amount) 'totalAmount' FROM t_ctr_contract a LEFT JOIN t_bs_company b ON b.id = a.company_id LEFT JOIN t_bs_area c on c.code =b.province_code
a.business_type = 'ZY-BB' AND a.contract_status != 'C' AND a.contract_type = 'S'
AND DATE_FORMAT(a.contract_time, '%Y-%m')>=#{monthBegin}
and DATE_FORMAT(a.contract_time, '%Y-%m')<=#{monthEnd}
and a.match_credit_flg =#{matchCreditFlg}
and a.dept_id = #{deptId}
GROUP BY b.province_code,c.name order by totalAmount desc
